    ]
  },
  "extraction": {
    "status": "candidates_found",
    "extracted_at": "2026-06-12T23:04:48",
    "extractor": "agent",
    "summary": "Paper reanalyzes 40 B-type stars from the MMT HVS survey, obtaining spectrophotometric distances and performing kinematic analysis for 37 of them. 25 stars are treated as possibly unbound: the 22 HVS-numbered stars (HVS1, HVS4–HVS24) and three originally bound stars that become unbound or ambiguous (B485, B1085, B576). 15 B-numbered stars are concluded to be likely bound and are excluded.",
    "tooling": null
  },
  "method_chain": [
    {
      "id": "step-01",
      "depends_on": [],
      "step_type": "input_catalog",
      "summary": "Input data: MMT HVS survey flux-calibrated spectra (Warren Brown), Gaia DR2 astrometry and photometry, HST proper motions for 15 stars, and photometric catalogs (GALEX, SDSS, Pan-STARRS1, Gaia, UKIDSS, VISTA, SkyMapper, etc.).",
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2003.12766/arxiv_source/aa.tex",
          "start_line": 99,
          "end_line": 99,
          "context": "extend the spectrophotometric analysis to 40 out of the 42 high-velocity outliers of the MMT HVS sample."
        },
        {
          "kind": "text",
          "path": "literature/2003.12766/arxiv_source/aa.tex",
          "start_line": 272,
          "end_line": 272,
          "context": "Photometric data were compiled from a variety of surveys."
        },
        {
          "kind": "text",
          "path": "literature/2003.12766/arxiv_source/aa.tex",
          "start_line": 288,
          "end_line": 288,
          "context": "Proper motions were mainly taken from Gaia DR2."
        }
      ]
    },
    {
      "id": "step-02",
      "depends_on": [
        "step-01"
      ],
      "step_type": "cross_match",
      "summary": "Cross-match of MMT target list with Gaia DR2 and HST catalogs; when both Gaia and HST proper motions are available, the more precise measurement is selected (HST for HVS1, HVS10, HVS12, HVS13; Gaia for B711).",
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2003.12766/arxiv_source/aa.tex",
          "start_line": 288,
          "end_line": 288,
          "context": "we chose the more precise measurement when Gaia as well as HST proper motions were available."
        }
      ]
    },
    {
      "id": "step-03",
      "depends_on": [
        "step-01"
      ],
      "step_type": "radial_velocity_measurement",
      "summary": "Radial velocity (v_rad) derived from simultaneous fitting of MMT flux-calibrated spectra using χ² minimization. The fit uses a grid of non-LTE model spectra and includes four parameters: effective temperature, surface gravity, projected rotational velocity, and radial velocity.",
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2003.12766/arxiv_source/aa.tex",
          "start_line": 150,
          "end_line": 150,
          "context": "We were thus left with four fitting parameters ... the radial velocity v_rad."
        }
      ]
    },
    {
      "id": "step-04",
      "depends_on": [
        "step-01"
      ],
      "step_type": "stellar_parameter_inference",
      "summary": "Spectroscopic analysis: from the same fit, derive effective temperature T_eff, surface gravity log(g), and projected rotational velocity v sin(i). The fit also determines interstellar reddening E(B−V) and a distance scaling factor, with R_V fixed at 3.1.",
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2003.12766/arxiv_source/aa.tex",
          "start_line": 132,
          "end_line": 150,
          "context": "The spectral analysis strategy basically followed Irrgang et al. (2014). ... we were left with four fitting parameters: T_eff, log(g), v sin(i), and v_rad."
        }
      ]
    },
    {
      "id": "step-05",
      "depends_on": [
        "step-01",
        "step-04"
      ],
      "step_type": "photometric_or_sed_modeling",
      "summary": "SED fitting: Observed spectral energy distributions (SEDs) are constructed from compiled photometry and compared to synthetic SEDs based on Atlas12 models with parameters fixed to spectroscopic values. Only angular diameter Θ and color excess E(B−V) are fitted to derive Θ and reddening.",
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2003.12766/arxiv_source/aa.tex",
          "start_line": 276,
          "end_line": 276,
          "context": "The resulting observed SEDs were compared to synthetic ones based on Atlas12 model computations ... we were left with only two free fitting parameters, the angular diameter Θ and the color excess E(B−V)."
        }
      ]
    },
    {
      "id": "step-06",
      "depends_on": [
        "step-04",
        "step-05"
      ],
      "step_type": "distance_estimation",
      "summary": "Spectrophotometric distances: combine angular diameters Θ = 2 R/d with stellar radii R = (G M / g)^{1/2} derived from spectroscopic surface gravity and masses from evolutionary tracks. For B598 and B576 alternative distances are also computed.",
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2003.12766/arxiv_source/aa.tex",
          "start_line": 280,
          "end_line": 281,
          "context": "The resulting angular diameters ... were combined with the stellar radii ... to calculate the spectrophotometric distances d."
        }
      ]
    },
    {
      "id": "step-07",
      "depends_on": [
        "step-02"
      ],
      "step_type": "quality_filter",
      "summary": "Astrometric quality filter: the renormalised unit weight error (RUWE) from Gaia DR2 is used as the primary quality indicator. All objects have RUWE < 1.4.",
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2003.12766/arxiv_source/aa.tex",
          "start_line": 288,
          "end_line": 288,
          "context": "For all objects in the sample, RUWE is below the recommended value of 1.4."
        }
      ]
    },
    {
      "id": "step-08",
      "depends_on": [],
      "step_type": "solar_position_and_motion",
      "summary": "Solar position and motion parameters are not explicitly stated in this paper; they are presumably from Paper II (2018A&A...620A..48I).",
      "parameters": []
    },
    {
      "id": "step-09",
      "depends_on": [
        "step-02",
        "step-03",
        "step-06",
        "step-07",
        "step-08"
      ],
      "step_type": "velocity_calculation",
      "summary": "Transformation to a right-handed Cartesian Galactic coordinate system. Compute Galactocentric positions (x,y,z) and velocities (v_x,v_y,v_z), Galactic rest-frame velocity v_Grf, and ejection velocities.",
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2003.12766/arxiv_source/aa.tex",
          "start_line": 307,
          "end_line": 307,
          "context": "The quantities shown there are based on a right-handed Cartesian Galactic coordinate system."
        }
      ]
    },
    {
      "id": "step-10",
      "depends_on": [],
      "step_type": "galactic_potential_model",
      "summary": "Two Galactic mass models: Model I (revised Allen & Santillan 1991) and Model II (flat rotation curve, Wilkinson & Evans 1999). Both are calibrated using the same constraints and are consistent with Gaia DR2.",
      "parameters": [
        {
          "name": "potential_name",
          "raw_value": "Model I (revised Allen & Santillan 1991)",
          "value": "Model I",
          "source_refs": [
            {
              "kind": "text",
              "path": "literature/2003.12766/arxiv_source/aa.tex",
              "start_line": 293,
              "end_line": 293,
              "context": "Model I is a revision of the popular model by Allen & Santillan (1991) and Model II is based on ... Wilkinson & Evans (1999)."
            }
          ]
        },
        {
          "name": "potential_name",
          "raw_value": "Model II (flat rotation curve, Wilkinson & Evans 1999)",
          "value": "Model II",
          "source_refs": [
            {
              "kind": "text",
              "path": "literature/2003.12766/arxiv_source/aa.tex",
              "start_line": 293,
              "end_line": 293,
              "context": "Model II is based on the flat rotation curve model by Wilkinson & Evans (1999)."
            }
          ]
        }
      ]
    },
    {
      "id": "step-11",
      "depends_on": [
        "step-09",
        "step-10",
        "step-08",
        "step-04"
      ],
      "step_type": "orbit_integration",
      "summary": "Orbit integration: Monte Carlo backward integration (1.5 million trials) of trajectories for up to 15 Gyr, accounting for uncertainties. Only orbits that cross the Galactic plane within the upper 99% confidence limit of the stellar age are considered.",
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2003.12766/arxiv_source/aa.tex",
          "start_line": 284,
          "end_line": 284,
          "context": "Propagation of uncertainties ... was achieved using a standard Monte Carlo approach with 1.5 million realizations."
        },
        {
          "kind": "text",
          "path": "literature/2003.12766/arxiv_source/aa.tex",
          "start_line": 297,
          "end_line": 298,
          "context": "we considered only those out of the 1.5 million Monte Carlo orbits that cross the Galactic plane within the upper 99% confidence limit for the respective stellar age."
        }
      ]
    },
    {
      "id": "step-12",
      "depends_on": [
        "step-09",
        "step-10",
        "step-11"
      ],
      "step_type": "escape_or_bound_assessment",
      "summary": "Bound/unbound assessment: Compute local escape velocity v_esc, the escape velocity excess (v_Grf − v_esc), and the bound probability P_b (percentage) from the Monte Carlo orbits.",
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2003.12766/arxiv_source/aa.tex",
          "start_line": 307,
          "end_line": 307,
          "context": "The Galactic rest-frame velocity v_Grf, the local Galactic escape velocity v_esc, (...), the ejection velocity v_ej, and the flight time τ_flight are listed."
        },
        {
          "kind": "text",
          "path": "literature/2003.12766/arxiv_source/aa.tex",
          "start_line": 440,
          "end_line": 442,
          "context": "Whether a star is bound to the Galaxy or not is determined by the Galactic potential, in particular the mass of the Galactic dark matter halo."
        }
      ]
    },
    {
      "id": "step-13",
      "depends_on": [
        "step-11",
        "step-04"
      ],
      "step_type": "origin_assessment",
      "summary": "Origin assessment: classify stars into origin categories (unconstrained, outer rim, disk origin) based on plane-crossing locations of Monte Carlo orbits; compare flight times to evolutionary ages; determine ejection velocities at plane crossing.",
      "source_refs": [
        {
          "kind": "text",
          "path": "literature/2003.12766/arxiv_source/aa.tex",
          "start_line": 322,
          "end_line": 322,
          "context": "we group the stars in three categories based on their inferred spatial origin."
        },
        {
          "kind": "text",
          "path": "literature/2003.12766/arxiv_source/aa.tex",
          "start_line": 297,
          "end_line": 297,
          "context": "Tracing back the trajectories ... gave us information about their spatial origin within the Galactic plane."
        }
      ]
    }
  ],
